INSERT INTO `weibo` VALUES ('Qwn0VExYo', '1781372535', ':我曾在西湖边上买过一根香蕉，边吃边想，什么时候能在这么美的城市开一场演唱会。直到差点被湖边的风吹感冒，我才决定从长计议，先从西湖醋鱼开始攻克。\n很多年过去了，因为大家的抬爱，终于让我有机会来到杭州开启我的演唱会之旅。你、你、还有你、咱们该聚聚了，一个都不能少。我负责唱，你负责叫，他们负责微笑。\n时间：4月17/18/19日\n地点：杭州奥体AT中心体育馆 \n#微博演出季##徐良时间折叠巡回演唱会#', '', 'https://wx4.sinaimg.cn/large/6a2d9677ly1ib8xdng9dej23wq5v5e89.jpg', '', 1, '无', '无', '2026-03-16 17:39:00', '华为Mate 80 RS', 4011, 2629, 1264);
