  `update_time` datetime(6) NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6) COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '备注',
  `album_id` int NOT NULL AUTO_INCREMENT COMMENT '专辑ID',
  `name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL COMMENT '专辑名称',
  `alias` json NULL COMMENT '专辑别名',
  `netease_album_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '关联第三方网易云专辑ID',
  `artist_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL COMMENT '歌手ID',
  `artist_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL COMMENT '歌手名称',
  `pic_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '专辑封面图片URL',
  `blur_pic_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '模糊封面图片URL',
  `company` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '发行公司',
  `publish_time` date NULL DEFAULT NULL COMMENT '发行日期',
  `type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '专辑类型',
  `sub_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '专辑子类型',
  `size` int NOT NULL DEFAULT 0 COMMENT '专辑包含歌曲数量',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL COMMENT '详细介绍',
  `brief_desc` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '简短描述',
  PRIMARY KEY (`album_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 45 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_zh_0900_as_cs COMMENT = '音乐专辑表' ROW_FORMAT = Dynamic;

