-- ----------------------------
-- Table structure for music_song
-- ----------------------------
DROP TABLE IF EXISTS `music_song`;
CREATE TABLE `music_song`  (
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL DEFAULT '0' COMMENT '删除标志',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL DEFAULT '0' COMMENT '状态',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime(6) NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime(6) NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6) COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '备注',
  `song_id` int NOT NULL AUTO_INCREMENT COMMENT '歌曲ID',
  `name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL COMMENT '歌曲名称',
  `alias` json NULL COMMENT '歌曲别名',
  `album_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL COMMENT '关联的专辑ID',
  `album_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL COMMENT '专辑名称',
  `album_cover` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '专辑封面URL',
  `audio_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '自建/永久音频流直链',
  `netease_song_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '关联第三方网易云歌曲ID',
  `qq_song_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '关联第三方QQ音乐歌曲ID',
  `duration_ms` int NOT NULL DEFAULT 0 COMMENT '歌曲时长（单位：毫秒）',
  `audio_size` bigint NOT NULL DEFAULT 0 COMMENT '音频文件大小(字节)',
  `audio_type` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NOT NULL DEFAULT 'mp3' COMMENT '音频格式',
  `bitrate` int NOT NULL DEFAULT 128000 COMMENT '音频码率',
  `tags` json NULL COMMENT '歌曲标签/流派',
  `release_date` date NULL DEFAULT NULL COMMENT '发行日期',
  `lyrics` text CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL COMMENT 'LRC标准歌词',
  `has_translation` tinyint NOT NULL DEFAULT 0 COMMENT '是否有歌词翻译（0无 1有）',
  `qq_music_page` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT 'QQ音乐网页链接',
  `netease_page` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT '网易云网页链接',
  `mv_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_zh_0900_as_cs NULL DEFAULT NULL COMMENT 'MV播放链接',
  `play_count` int NOT NULL DEFAULT 0 COMMENT '累计播放次数',
  `like_count` int NOT NULL DEFAULT 0 COMMENT '累计收藏数',
  `share_count` int NOT NULL DEFAULT 0 COMMENT '累计分享数',
  `sort_order` int NOT NULL DEFAULT 0 COMMENT '排序权重',
  PRIMARY KEY (`song_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 390 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_zh_0900_as_cs COMMENT = '音乐歌曲表' ROW_FORMAT = Dynamic;

